export async function fetchWeather(city: string): Promise<WeatherResponse> {
  const url = `https://api.openweathermap.org/data/2.5/weather?q=${encodeURIComponent(city)}&appid=${import.meta.env.VITE_WEATHER_API_KEY}&units=metric`;

  const response = await fetch(url);

  if (!response.ok) {
    throw new Error(`Weather API failed: ${response.status}`);
  }

  return response.json() as Promise<WeatherResponse>;
}

async function load(city: string) {
  setIsLoading(true);
  setError(null);
  try {
    const data = await fetchWeather(city);
    setWeather(data);
  } catch (err) {
    setError(err instanceof Error ? err.message : 'Something went wrong');
  } finally {
    setIsLoading(false);
  }
}

export interface WeatherCondition {
  main: string;
  description: string;
  icon: string;
}

export interface WeatherMain {
  temp: number;
  feels_like: number;
  humidity: number;
}

export interface WeatherResponse {
  name: string;
  main: WeatherMain;
  weather: WeatherCondition[];
  wind: { speed: number };
}

const [city, setCity] = useState('');
const [query, setQuery] = useState<string | null>(null);

// Fetch when query changes — query is set on form submit
useEffect(() => {
  if (!query) return;

  let cancelled = false;

  async function load() {
    setIsLoading(true);
    setError(null);
    try {
      const data = await fetchWeather(query);
      if (!cancelled) setWeather(data);
    } catch (err) {
      if (!cancelled) setError(getErrorMessage(err));
    } finally {
      if (!cancelled) setIsLoading(false);
    }
  }

  load();
  return () => { cancelled = true; };
}, [query]);

